import axios from 'axios';

// ─────────────────────────────────────────────────────────────
// AXIOS INSTANCE
// ─────────────────────────────────────────────────────────────
const API = axios.create({
  baseURL: '/api',
  headers: { 'Content-Type': 'application/json' },
});

// ─────────────────────────────────────────────────────────────
// REQUEST INTERCEPTOR
// Attach JWT token to every request automatically
// ─────────────────────────────────────────────────────────────
API.interceptors.request.use(
  (config) => {
    const user = JSON.parse(localStorage.getItem('user') || 'null');
    if (user?.token) {
      config.headers.Authorization = `Bearer ${user.token}`;
    }

    // CRITICAL FIX: If sending FormData, remove Content-Type so
    // browser sets it automatically with the correct multipart boundary.
    // Without this, file uploads always fail (0 files received by multer).
    if (config.data instanceof FormData) {
      delete config.headers['Content-Type'];
    }

    return config;
  },
  (error) => Promise.reject(error)
);

// ─────────────────────────────────────────────────────────────
// RESPONSE INTERCEPTOR
// Global error handling — logs errors, handles 401 auto-logout
// ─────────────────────────────────────────────────────────────
API.interceptors.response.use(
  (response) => response,
  (error) => {
    const message =
      error.response?.data?.message ||
      error.response?.data?.error ||
      error.message ||
      'Something went wrong';

    // Auto logout if token expired or invalid
    if (error.response?.status === 401) {
      const publicRoutes = ['/auth/login', '/auth/register'];
      const isPublic = publicRoutes.some((r) =>
        error.config?.url?.includes(r)
      );
      if (!isPublic) {
        localStorage.removeItem('user');
        window.location.href = '/login';
      }
    }

    // Attach clean message to error so components can use it easily:
    // toast.error(err.message) instead of err.response?.data?.message
    error.message = message;
    return Promise.reject(error);
  }
);

// ─────────────────────────────────────────────────────────────
// AUTH
// ─────────────────────────────────────────────────────────────
export const register      = (data) => API.post('/auth/register', data);
export const login         = (data) => API.post('/auth/login', data);
export const getProfile    = ()     => API.get('/auth/profile');
export const updateProfile = (data) => API.put('/auth/profile', data);

// ─────────────────────────────────────────────────────────────
// PRODUCTS
// NOTE: specific string routes (/featured, /categories, /my)
// must be defined BEFORE /:id in your productRoutes.js or they
// will be caught by the /:id handler and fail.
// ─────────────────────────────────────────────────────────────
export const getProducts   = (params) => API.get('/products', { params });
export const getProduct    = (id)     => API.get(`/products/${id}`);
export const getFeatured   = ()       => API.get('/products/featured');
export const getCategories = ()       => API.get('/products/categories');
export const getMyProducts = ()       => API.get('/products/my');
export const getAllProducts = (params) => API.get('/products', { params });

// createProduct and updateProduct accept either FormData (with files)
// or a plain object. The request interceptor above handles Content-Type.
export const createProduct  = (data)     => API.post('/products', data);
export const updateProduct  = (id, data) => API.put(`/products/${id}`, data);
export const deleteProduct  = (id)       => API.delete(`/products/${id}`);
export const addReview      = (id, data) => API.post(`/products/${id}/reviews`, data);
export const toggleFeatured = (id)       => API.patch(`/products/${id}/featured`);

// ─────────────────────────────────────────────────────────────
// ORDERS
// ─────────────────────────────────────────────────────────────
export const createOrder      = (data)     => API.post('/orders', data);
export const getMyOrders      = ()         => API.get('/orders/myorders');
export const getOrder         = (id)       => API.get(`/orders/${id}`);
export const payOrder         = (id, data) => API.put(`/orders/${id}/pay`, data);
export const getAllOrders      = ()         => API.get('/orders');
export const updateOrderStatus = (id, data) => API.put(`/orders/${id}/status`, data);

// ─────────────────────────────────────────────────────────────
// CART
// ─────────────────────────────────────────────────────────────
export const getCart        = ()           => API.get('/cart');
export const addToCart      = (data)       => API.post('/cart', data);
export const updateCartItem = (id, data)   => API.put(`/cart/${id}`, data);
export const removeFromCart = (id)         => API.delete(`/cart/${id}`);
export const clearCart      = ()           => API.delete('/cart');

// ─────────────────────────────────────────────────────────────
// WISHLIST
// ─────────────────────────────────────────────────────────────
export const getWishlist     = ()   => API.get('/wishlist');
export const toggleWishlist  = (id) => API.post(`/wishlist/${id}`);

// ─────────────────────────────────────────────────────────────
// COUPONS
// ─────────────────────────────────────────────────────────────
export const applyCoupon  = (data) => API.post('/coupons/apply', data);
export const getCoupons   = ()     => API.get('/coupons');
export const createCoupon = (data) => API.post('/coupons', data);
export const toggleCoupon = (id)   => API.put(`/coupons/${id}/toggle`);
export const deleteCoupon = (id)   => API.delete(`/coupons/${id}`);

// ─────────────────────────────────────────────────────────────
// ADMIN
// ─────────────────────────────────────────────────────────────
export const getDashboard       = ()   => API.get('/admin/dashboard');
export const getUsers           = ()   => API.get('/admin/users');
export const blockUser          = (id) => API.put(`/admin/users/${id}/block`);
export const getPendingProducts = ()   => API.get('/admin/products/pending');
export const approveProduct     = (id) => API.put(`/admin/products/${id}/approve`);

export default API;
